import pytest
import requests

BASE_URL = "http://hr-app/api"
MIN_HOURS_BOUNDARY = 0

def test_hr_admin_update_timesheet_boundary_zero_hours(
    hr_admin_token,
    existing_timesheet_id,
    timesheet_min_hours_rule,  # <fixture>: returns True if 0 is valid per business rule
):
    payload = {
        "employee_id": "emp-001",
        "period_start": "2024-06-01",
        "period_end": "2024-06-07",
        "total_hours": MIN_HOURS_BOUNDARY,
        "status": "submitted"
    }
    headers = {"Authorization": f"Bearer {hr_admin_token}"}
    resp = requests.put(
        f"{BASE_URL}/timesheets/{existing_timesheet_id}",
        json=payload,
        headers=headers,
    )
    if timesheet_min_hours_rule:
        assert resp.status_code in (200, 201), f"0 hours should be valid, got {resp.status_code}"
    else:
        assert resp.status_code == 400, f"0 hours should be invalid, got {resp.status_code}"
